import React from 'react'
import logoImg from '../assets/frikt.png'

export default function Login() {
    const isAuth = useSelector(selectIsAuth);
  const dispatch = useDispatch();
  const {
    register,
    handleSubmit,
    formState: { errors, isValid },
  } = useForm({
    mode: "onChange",
  });

  const onSubmit = async (values) => {
    const data = await dispatch(fetchAuth(values));
    if (!data.payload) {
      return alert("Cant auth");
    }
    if ("token" in data.payload) {
      window.localStorage.setItem("token", data.payload.token);
    }
  };

  if (isAuth) {
    return <Navigate to="/" />;
  }

  return (
    <div className='grid grid-cols-1 sm:grid-cols-2 h-screen w-full'>
        <div className='hidden sm:block'>
            <img className='w-full h-full object-cover' src={logoImg} alt="" />
        </div>
        <div className='bg-gray-800 flex flex-col justify-center'>
            <form action="" className='max-w-[400px] w-full mx-auto bg-gray-900 px-8 py-8 rounded-lg'>
                <h2 className='text-4x1 dark:text-white font-bold text-center'>Sing In</h2>
                <div className='flex flex-col text-gray-400 py-2'>
                    <label htmlFor="" >User Name</label>
                    <input type="text" className='rounded-lg bg-gray-700 mt-2 p-2 focus:border-blue-500 focus:bg-gray-800 focus:outline-none'/>
                </div>
                <div className='flex flex-col text-gray-400 py-2'>
                    <label htmlFor="" >Password</label>
                    <input type="password" className='rounded-lg bg-gray-700 mt-2 p-2 focus:border-blue-500 focus:bg-gray-800 focus:outline-none'/>
                </div>
                <button className='w-full my-s py-2 bg-sky-500 shadow-lg shadow-sky-500/50'>Sing In</button>
            </form>
        </div>
    </div>
  )
}
